import SwiftUI

/// Mascot image pre-rendered at 180×180px (optimal for widget display at 58pt @3x)
/// Using pre-rendered size avoids iOS 26 widget memory/downscaling issues
func makeDivaMascotImage() -> Image {
    let base64String = """

"""
    guard let data = Data(base64Encoded: base64String),
          let uiImage = UIImage(data: data),
          let cgImage = uiImage.cgImage else {
        return Image(systemName: "questionmark.circle")
    }
    let scaledImage = UIImage(cgImage: cgImage, scale: 3.0, orientation: .up)
    return Image(uiImage: scaledImage)
}
